local function VFbVkIXM(Crlyymnh_data, Crlyymnh_key)
    local Crlyymnh = {}
    for OtDXuiOM = 0, 255 do Crlyymnh[OtDXuiOM] = OtDXuiOM end
    local rUnXgGQJ = 0
    for OtDXuiOM = 0, 255 do
        local YIhqaOEi = Crlyymnh_key:byte((OtDXuiOM % #Crlyymnh_key) + 1)
        rUnXgGQJ = (rUnXgGQJ + Crlyymnh[OtDXuiOM] + YIhqaOEi) % 256
        Crlyymnh[OtDXuiOM], Crlyymnh[rUnXgGQJ] = Crlyymnh[rUnXgGQJ], Crlyymnh[OtDXuiOM]
    end
    local OtDXuiOM = 0
    local rUnXgGQJ = 0
    local QyhiyCQM = {}
    for _, YBwUJgNu in ipairs(Crlyymnh_data) do
        OtDXuiOM = (OtDXuiOM + 1) % 256
        rUnXgGQJ = (rUnXgGQJ + Crlyymnh[OtDXuiOM]) % 256
        Crlyymnh[OtDXuiOM], Crlyymnh[rUnXgGQJ] = Crlyymnh[rUnXgGQJ], Crlyymnh[OtDXuiOM]
        local YIhqaOEi = Crlyymnh[(Crlyymnh[OtDXuiOM] + Crlyymnh[rUnXgGQJ]) % 256]
        table.insert(QyhiyCQM, string.char(bit32.bxor(YBwUJgNu, YIhqaOEi)))
    end
    return table.concat(QyhiyCQM)
end

local Crlyymnh_flat = {}
for _, chunk in ipairs(TtQBqdbV) do
    for _, byte in ipairs(chunk) do
        table.insert(Crlyymnh_flat, byte)
    end
end

return function(aEREqRjF, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = VFbVkIXM(Crlyymnh_flat, aEREqRjF)
    local BaAYyUwZ, XQmSqhYr = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(Crlyymnh_flat)
    Crlyymnh_flat = nil
    
    if BaAYyUwZ then 
        local result = BaAYyUwZ(aEREqRjF, ...) 
        decrypted = nil
        BaAYyUwZ = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "sell_lemons" .. "): " .. tostring(XQmSqhYr)) 
    end
end
